import React from 'react';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import List from '@mui/material/List';
import ListItemButton from '@mui/material/ListItemButton';
import ListItemIcon from '@mui/material/ListItemIcon';
import ListItemText from '@mui/material/ListItemText';
import CircularProgress from '@mui/material/CircularProgress';
import MeetingRoomIcon from '@mui/icons-material/MeetingRoom';
import { formatShortRelativeTime } from '../utils/roomMeta';

const ChatRoomSidebar = ({
  rooms,
  currentRoomId,
  onRoomClick,
  loading,
  title = 'Phòng có sẵn',
}) => {
  const safeRooms = Array.isArray(rooms) ? rooms : [];

  return (
    <Box
      sx={{
        flex: 1,
        minHeight: 0,
        height: '100%',
        display: 'flex',
        flexDirection: 'column',
      }}
    >
      <Box sx={{ px: 2, pt: 2, pb: 1.25 }}>
        <Typography variant="subtitle2" fontWeight={800} color="primary.dark" sx={{ letterSpacing: 0.02 }}>
          {title}
        </Typography>
      </Box>

      {loading ? (
        <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
          <CircularProgress size={28} />
        </Box>
      ) : null}

      {!loading && safeRooms.length === 0 ? (
        <Typography variant="body2" color="text.secondary" sx={{ px: 2, py: 2 }}>
          Không có phòng nào.
        </Typography>
      ) : null}

      <List dense={false} disablePadding sx={{ flex: 1, overflow: 'auto', px: 1, pb: 2 }}>
        {safeRooms.map((room) => {
          const selected = room?.id === currentRoomId;
          const last = room?.last_message;
          const rel = last?.created ? formatShortRelativeTime(last.created) : '';
          const metaLine = last
            ? [`Tin nhắn của ${last.user || '?'}`, rel].filter(Boolean).join(' · ')
            : '';

          const secondary = (
            <Box sx={{ mt: 0.35 }}>
              {last ? (
                <Typography
                  component="div"
                  variant="body2"
                  noWrap
                  sx={{
                    fontSize: '0.8125rem',
                    lineHeight: 1.35,
                    fontWeight: 400,
                    opacity: selected ? 0.95 : 0.92,
                    color: selected ? 'inherit' : 'text.primary',
                  }}
                >
                  {last.preview || '…'}
                </Typography>
              ) : (
                <Typography
                  variant="body2"
                  sx={{
                    fontSize: '0.8125rem',
                    opacity: selected ? 0.9 : 0.75,
                    color: selected ? 'inherit' : 'text.secondary',
                  }}
                >
                  Chưa có tin
                </Typography>
              )}
              {metaLine ? (
                <Typography
                  variant="caption"
                  sx={{
                    display: 'block',
                    mt: 0.35,
                    fontSize: '0.7rem',
                    opacity: selected ? 0.82 : 0.62,
                    color: selected ? 'inherit' : 'text.secondary',
                  }}
                >
                  {metaLine}
                </Typography>
              ) : null}
            </Box>
          );

          return (
            <ListItemButton
              key={room.id}
              selected={selected}
              onClick={() => onRoomClick(room)}
              alignItems="flex-start"
              sx={{
                borderRadius: 1.5,
                mb: 0.5,
                py: 1.1,
                '&.Mui-selected': {
                  bgcolor: 'primary.main',
                  color: 'primary.contrastText',
                  '& .MuiTypography-root': { color: 'inherit' },
                  '& .MuiSvgIcon-root': { color: 'inherit' },
                  '&:hover': { bgcolor: 'primary.dark' },
                },
              }}
            >
              <ListItemIcon sx={{ minWidth: 36, mt: 0.35, color: selected ? 'inherit' : 'primary.main' }}>
                <MeetingRoomIcon fontSize="small" aria-hidden />
              </ListItemIcon>
              <ListItemText
                primary={room.name || room.id}
                secondary={secondary}
                primaryTypographyProps={{
                  noWrap: true,
                  variant: 'subtitle1',
                  fontWeight: selected ? 800 : 700,
                  fontSize: '1.0625rem',
                  lineHeight: 1.25,
                  letterSpacing: '-0.01em',
                }}
                secondaryTypographyProps={{ component: 'div' }}
              />
            </ListItemButton>
          );
        })}
      </List>
    </Box>
  );
};

export default ChatRoomSidebar;
